mapper.select:
SELECT f.id, f.user_id, u.nick_name AS user_name, f.feedback_type, f.title, f.content, f.images, f.contact_info, f.status, f.handle_user_id, h.nick_name AS handle_user_name, f.handle_result, f.handle_time, f.satisfaction, f.remark, f.create_time FROM sp_feedback f LEFT JOIN sys_user u ON f.user_id = u.user_id LEFT JOIN sys_user h ON f.handle_user_id = h.user_id
AND f.user_id = #{ew.userId}
AND u.nick_name LIKE CONCAT('%', #{ew.userName}, '%')
AND f.feedback_type = #{ew.feedbackType}
AND f.title LIKE CONCAT('%', #{ew.title}, '%')
AND f.status = #{ew.status}
AND f.handle_user_id = #{ew.handleUserId}
ORDER BY f.create_time DESC
